      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: true,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: false,
        dblclick: false,
        mousedown: false,
